mapper.sql:
FROM ( SELECT AA.*, ROW_NUMBER() OVER(
ORDER BY COUNT ${sortDirect}
ORDER BY BST_TYPE_NAME ${sortDirect}
ORDER BY BST_TITLE ${sortDirect}
ORDER BY BST_UI_NAME ${sortDirect}
ORDER BY BST_REGDT ${sortDirect}
ORDER BY BST_KEYNO DESC
) RNUM FROM( SELECT BST_KEYNO , ROWNUM as COUNT , TO_CHAR(BST_REGDT,'YYYY-MM-dd HH24:mi:ss') BST_REGDT , NVL(U.UI_REP_NAME,BST_REGNM) BST_UI_NAME , BST_TITLE , CASE WHEN B.BST_TYPE = 'list' THEN '리스트' WHEN B.BST_TYPE = 'detail' THEN '상세' WHEN B.BST_TYPE = 'insert' THEN '등록' END BST_TYPE_NAME FROM b_board_skin_template B LEFT JOIN u_userinfo U ON B.BST_REGNM = U.UI_KEYNO WHERE BST_DElETE = 'N' )AA WHERE 1=1
AND COUNT LIKE '%' || #{item.searchKeyword} || '%'
AND BST_TYPE_NAME LIKE '%' || #{item.searchKeyword} || '%'
AND BST_TITLE LIKE '%' || #{item.searchKeyword} || '%'
AND BST_UI_NAME LIKE '%' || #{item.searchKeyword} || '%'
AND BST_REGDT LIKE '%' || #{item.searchKeyword} || '%'
AND ( COUNT LIKE '%' || #{item.searchKeyword} || '%' OR BST_TYPE_NAME LIKE '%' || #{item.searchKeyword} || '%' OR BST_TITLE LIKE '%' || #{item.searchKeyword} || '%' OR BST_UI_NAME LIKE '%' || #{item.searchKeyword} || '%' OR BST_REGDT LIKE '%' || #{item.searchKeyword} || '%' )
) B

mapper.update:
UPDATE b_board_skin_template
SET 
	BST_TITLE = #{BST_TITLE},
	BST_FORM = #{BST_FORM},
	BST_TYPE = #{BST_TYPE}
WHERE BST_KEYNO  = #{BST_KEYNO}

mapper.sql:
FROM ( SELECT AA.*, ROW_NUMBER() OVER(
ORDER BY COUNT ${sortDirect}
ORDER BY BSP_TITLE ${sortDirect}
ORDER BY LIST_TITLE ${sortDirect}
ORDER BY DETAIL_TITLE ${sortDirect}
ORDER BY INSERT_TITLE ${sortDirect}
ORDER BY BSP_KEYNO DESC
) RNUM FROM( SELECT BSP_KEYNO , ROWNUM as COUNT , TO_CHAR(BSP_REGDT,'YYYY-MM-dd HH24:mi:ss') BSP_REGDT , NVL(U.UI_REP_NAME,BSP_REGNM) BSP_UI_NAME , BSP_TITLE , CASE WHEN B.BSP_LIST_KEYNO = 'list' then '기본 리스트 폼' WHEN B.BSP_LIST_KEYNO = 'no_detail' then '상세페이지 없는 리스트 폼' WHEN B.BSP_LIST_KEYNO = 'gallery' then '갤러리 폼' WHEN B.BSP_LIST_KEYNO = 'calendar' then '캘린더 폼' ELSE (SELECT BST_TITLE FROM b_board_skin_template WHERE BST_KEYNO = B.BSP_LIST_KEYNO ) END LIST_TITLE , CASE WHEN B.BSP_DETAIL_KEYNO = 'no' then '사용안함' WHEN B.BSP_DETAIL_KEYNO = 'normal' then '기본 상세페이지 폼' ELSE (SELECT BST_TITLE FROM b_board_skin_template WHERE BST_KEYNO = B.BSP_DETAIL_KEYNO ) END DETAIL_TITLE , CASE WHEN B.BSP_INSERT_KEYNO = 'normal' then '기본 등록 폼' ELSE (SELECT BST_TITLE FROM b_board_skin_template WHERE BST_KEYNO = B.BSP_INSERT_KEYNO ) END INSERT_TITLE FROM b_board_skin_package B LEFT JOIN u_userinfo U ON B.BSP_REGNM = U.UI_KEYNO WHERE BSP_DElETE = 'N' )AA WHERE 1=1
AND COUNT LIKE '%' || #{item.searchKeyword} || '%'
AND BSP_TITLE LIKE '%' || #{item.searchKeyword} || '%'
AND LIST_TITLE LIKE '%' || #{item.searchKeyword} || '%'
AND DETAIL_TITLE LIKE '%' || #{item.searchKeyword} || '%'
AND INSERT_TITLE LIKE '%' || #{item.searchKeyword} || '%'
AND ( COUNT LIKE '%' || #{item.searchKeyword} || '%' OR BSP_TITLE LIKE '%' || #{item.searchKeyword} || '%' OR LIST_TITLE LIKE '%' || #{item.searchKeyword} || '%' OR DETAIL_TITLE LIKE '%' || #{item.searchKeyword} || '%' OR INSERT_TITLE LIKE '%' || #{item.searchKeyword} || '%' )
)A

mapper.select:
 SELECT BST_FORM 
FROM b_board_skin_template 
WHERE BST_KEYNO = #{BST_KEYNO}
